import{_ as e,o as t,c as s,ag as i}from"./chunks/framework.567niBhm.js";const k=JSON.parse('{"title":"在IDE中打开项目","description":"","frontmatter":{},"headers":[],"relativePath":"zh-cn/server/environment-setup/idea.md","filePath":"zh-cn/server/environment-setup/idea.md","lastUpdated":1774677665000}'),n={name:"zh-cn/server/environment-setup/idea.md"};function o(l,a,r,p,d,h){return t(),s("div",null,[...a[0]||(a[0]=[i('<h1 id="在ide中打开项目" tabindex="-1">在IDE中打开项目 <a class="header-anchor" href="#在ide中打开项目" aria-label="Permalink to &quot;在IDE中打开项目&quot;">​</a></h1><h2 id="下载源码" tabindex="-1">下载源码 <a class="header-anchor" href="#下载源码" aria-label="Permalink to &quot;下载源码&quot;">​</a></h2><p>通过git clone命令将项目克隆到本地:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> git@github.com:lishangbu/avalon.git</span></span></code></pre></div><h2 id="配置发工具" tabindex="-1">配置发工具 <a class="header-anchor" href="#配置发工具" aria-label="Permalink to &quot;配置发工具&quot;">​</a></h2><p>项目采用的是JDK25开发而成，在低于JDK25的环境下可能会出现一些莫名其妙的问题，建议使用JDK25以上版本。虽然我感觉我没有使用多少新特性。但项目大量使用了多行文本块以及record/Markdown 文档注释等新特性，因此，版本绝对不能低于JDK23。</p><p>JDK有多种方式，包括sdkman、homebrew、vfox、asdf等，笔者采用的是asdf，具体安装方式请参考各自官网。</p><p>个人推荐可以使用Intellij IDEA的新 具体可以通过File-&gt; Project Structure-&gt;Project-&gt;Project SDK-Download JDK一键配置。</p><p>为了开发体验，建议使用以下插件:</p><table tabindex="0"><thead><tr><th>插件</th><th>备注</th></tr></thead><tbody><tr><td><a href="https://plugins.jetbrains.com/plugin/6317-lombok" target="_blank" rel="noreferrer">Lombok</a></td><td>高版本IntelliJ IDEA内置此插件</td></tr><tr><td><a href="https://plugins.jetbrains.com/plugin/22455-spotless-applier" target="_blank" rel="noreferrer">Spotless Applier</a></td><td>使用spotless格式化代码，通过Settings &gt; Tools &gt; Actions on Save &gt; Run spotless 来启用</td></tr></tbody></table><p>之后就可以使用IDE打开对应项目了，</p><h3 id="生成运行必须的资源" tabindex="-1">生成运行必须的资源 <a class="header-anchor" href="#生成运行必须的资源" aria-label="Permalink to &quot;生成运行必须的资源&quot;">​</a></h3><p>从安全与仓库体积控制角度考虑，RSA 密钥与 IP 数据库不会始终放在仓库中。运行项目之前，建议先在项目根目录执行以下 Gradle 任务：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> generateRsaKeys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> downloadIpData</span></span></code></pre></div><p>如果需要强制刷新 IP 数据，可以增加下载 Token 与刷新参数：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./gradlew</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> downloadIpData</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -PipDbDownloadToken=your-token</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -PrefreshIpDb=true</span></span></code></pre></div><p>IP 数据的具体配置方式见 <a href="./ip2location.html"><code>IP2Location</code></a>。</p><h3 id="初始化数据库" tabindex="-1">初始化数据库 <a class="header-anchor" href="#初始化数据库" aria-label="Permalink to &quot;初始化数据库&quot;">​</a></h3><p>项目本身采用的是<code>postgres</code>数据库,用户只需要完成数据库的创建与配置。如果采用前文的docker-compose文件，那就什么都不需要改直接启动就行。项目的建表与数据初始化在开发环境下会在项目启动时自动通过JPA完成。 暂时没做其他数据库的支持。</p><h3 id="启动" tabindex="-1">启动 <a class="header-anchor" href="#启动" aria-label="Permalink to &quot;启动&quot;">​</a></h3><p>执行avalon-application模块avalon-standalone-server下的AvalonStandaloneServerApplication的main方法，IDE会启动一个可运行的Spring Boot项目了。</p><p>要想启动管理后台，则执行avalon-application模块下的avalon-admin-server的AvalonAdminApplication的main方法，IDE会启动一个可运行的Spring Boot管理后台项目了。</p>',22)])])}const g=e(n,[["render",o]]);export{k as __pageData,g as default};
